/** @since 5.0 */
export type FFPExecutionWarning = "AtLeastOneCostIsStrictlyNegative";

/**
 * The returned result of [executeFindPaths()](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraphService/#executeFindPaths) and [executeFindPathsAsynchronous()](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraphService/#executeFindPathsAsynchronous).
 *
 * @since 5.0
 * @beta
 */
export default interface CIMFilteredFindPathsResultJSON {
  /**
   * The returned type of `executeFindPaths` and `executeFindPathsAsynchronous`.
   *
   * @since 5.0
   */
  type: "CIMFilteredFindPathsResult";
  /**
   * Any errors encountered while executing filtered find path.
   *
   * @since 5.0
   */
  error?: CIMFilteredFindPathsError;
  /**
   * Warnings indicating why a path was not found.
   *
   * @since 5.0
   */
  configurationWarning: "None" | "AllOriginsAreExcluded" | "AllDestinationsAreExcluded" | "AllOptionalWaypointsAreExcluded" | "AtLeastOneMandatoryEntityWaypointIsExcluded" | "AtLeastOneMandatoryRelationshipWaypointIsExcluded" | "ReachedMaxPathLength";
  /**
   * Warnings indicating issues during pathfinding.
   *
   * @since 5.0
   */
  executionWarnings?: FFPExecutionWarning[];
  /**
   * Pathfinding statistics.
   *
   * @since 5.0
   */
  statistics: CIMFilteredFindPathsStatistics;
  /**
   * The paths returned.
   *
   * @since 5.0
   */
  paths: CIMFilteredFindPathsResultPaths;
}

/**
 * Errors returned in the result of [executeFindPaths()](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraphService/#executeFindPaths) and [executeFindPathsAsynchronous()](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraphService/#executeFindPathsAsynchronous).
 * When no path has been found, and `CIMFilteredFindPathsResultJSON.configurationWarning` is different from `None`, it is likely that the user made an unintended mistake in the configuration
 *
 * @since 5.0
 * @beta
 */
export interface CIMFilteredFindPathsError {
  /**
   * "CIMFilteredFindPathsError"
   *
   * @since 5.0
   */
  type: "CIMFilteredFindPathsError";
  /**
   * Errors indicating why the tool could not be executed.
   *
   * @since 5.0
   */
  error: "None" | "ConfigurationHasTooManyInputEntities" | "ConfigurationIsTooComplex" | "PunctualEventHasNoTime" | "DurativeEventHasNoTime" | "DurativeEventHasOneMissingTime" | "DurativeEventHasSwappedTimes" | "PropertyFilterSyntaxError";
  /**
   * Details about the error.
   *
   * @since 5.0
   */
  detailedErrorMessage: string;
}

/**
 * Represents the statistics related to an [executeFindPaths()](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraphService/#executeFindPaths) or [executeFindPathsAsynchronous()](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraphService/#executeFindPathsAsynchronous) search.
 * It contains the size of the local graph, and the number of openCypher "expansion" queries that have been issued
 *  to construct the local graph.
 *
 * The local graph is an in-memory graph used for pathfinding where
 * a node represents an entity in the Knowledge Graph and an edge represents
 * one or many parallel relationships in the Knowledge Graph.
 *
 * The local graph typically contains (much) less nodes than the Knowledge Graph, but enough nodes and edges
 * to ensure that the pathfinding results are accurate.
 * For example, to guarantee that all paths of length up to 'L' between 'A' and 'B' are present in the local graph,
 * we ensure that the sum of counts of "expansion" queries related to 'A' and 'B' is greater or equal to 'L'.
 *
 * @since 5.0
 * @beta
 */
export interface CIMFilteredFindPathsStatistics {
  /**
   * "CIMFilteredFindPathsStatistics"
   *
   * @since 5.0
   */
  type: "CIMFilteredFindPathsStatistics";
  /**
   * Number of nodes found in the local graph.
   *
   * @since 5.0
   */
  countLocalGraphNodes?: number;
  /**
   * Number of edges in the local graph. One edge in the local graph may represent multiple relationships when these relationships are parallel and equivalent with regard to pathfinding
   *
   * @since 5.0
   */
  countLocalGraphEdges?: number;
  /**
   * Gets or sets the count of expansion queries that were done to discover the neighborhood of some origin entities.
   *
   * @since 5.0
   */
  countOriginExpansionQueries?: number;
  /**
   * Gets or sets the count of expansion queries that were done to discover the neighborhood of some destination entities.
   *
   * @since 5.0
   */
  countDestinationExpansionQueries?: number;
  /**
   * Gets or sets the count of expansion queries that were done to discover the neighborhood of entity or relationship waypoints.
   *
   * @since 5.0
   */
  countWaypointsExpansionQueries?: number;
}

/**
 * Represents the paths found by an  [executeFindPaths()](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraphService/#executeFindPaths) and [executeFindPathsAsynchronous()](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraphService/#executeFindPathsAsynchronous) search.
 *
 *  We use a memory-optimized representation to avoid storing redundant information because
 *  it is often the case that a path shares some entities and relationships with many other paths,
 *  especially if the [Filtered Find Paths configuration](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/toolService/findPaths/CIMFilteredFindPathsConfiguration/)
 *  uses 'pathMode: "All"'.
 *
 *  Definition: a relationship group contains Knowledge Graph relationships associated to a single edge in the local graph.
 *
 *  Paths are encoded this way:
 *
 *  The path 'p' uses relationships groups `pathsBuffer[pathsEndIndex[p-1] .. pathsEndIndex[p]]`, and:
 *  - the origin of the first relationship group is the origin of the path
 *  - the destination of the last relationship group is the destination of the path
 *
 *  A path of length zero (with entity 'e') has a single relationship group containing no relationship and where the origin
 * and the destination are 'e'.
 *
 *  The relationships group 'g' has origin `entitiesUIDs[relationshipsGroupsFrom[g]]` and destination `entitiesUIDs[RelationshipsGroupsTo[g]]`.
 *  Its relationships are `relationshipsGroupsUIDsBuffer[relationshipsGroupsUIDsEndIndex[g-1] .. relationshipsGroupsUIDsEndIndex[g]]`.
 *
 *  If relationshipsFrom[i] >= 0, relationship `relationshipsGroupsUIDsBuffer[i]` has origin `entitiesUIDs[relationshipsFrom[i]]`
 *  otherwise the relationship has been deleted after pathfinding.
 *
 *  If relationshipsTo[i] >= 0, relationship `relationshipsGroupsUIDsBuffer[i]` has destination `entitiesUIDs[relationshipsTo[i]]`
 *  otherwise the relationship has been deleted after pathfinding.
 *
 *  Note that origin and destination of a relationship may not match origin and destination of the relationship group
 *  because the relationship can be traversed backwards.
 *
 * @since 5.0
 * @beta
 */
export interface CIMFilteredFindPathsResultPaths {
  /**
   * "CIMKGPaths"
   *
   * @since 5.0
   */
  type: "CIMKGPaths";
  /**
   * The list of entities that may be used in paths (not all entities are guaranteed to be used).
   *
   * @since 5.0
   */
  entitiesUIDs?: string[];
  /**
   * A list parallel to EntitiesUIDs representing entity type indices. If EntityTypes[i] >= 0, EntitiesUIDs[i] has type IndexedEntityTypes[EntityTypes[i]], otherwise the entity has been deleted after the find path operation.
   *
   * @since 5.0
   */
  entityTypes?: number[];
  /**
   * The list of entity types, indexed by `entityTypes`
   *
   * @since 5.0
   */
  indexedEntityTypes?: string[];
  /**
   * The list of relationships that may be used in paths (not all relationships are guaranteed to be used). The list may contain duplicate elements.
   *
   * @since 5.0
   */
  relationshipsGroupsUIDsBuffer?: string[];
  /**
   * A list parallel to `RelationshipsGroupsUIDsBuffer` representing relationship type indices. If RelationshipTypes[i] >= 0, RelationshipsGroupsUIDsBuffer[i] has type IndexedRelationshipTypes[RelationshipTypes[i]], otherwise the relationship has been deleted after the find path operation.
   *
   * @since 5.0
   */
  relationshipTypes?: number[];
  /**
   * The list of relationship types, indexed by `relationshipTypes`
   *
   * @since 5.0
   */
  indexedRelationshipTypes?: string[];
  /**
   * The list of relationship group's relationship end indices (indexes into `relationshipsGroupsUIDsBuffer`). Values must be positive.
   *
   * @since 5.0
   */
  relationshipsGroupsUIDsEndIndex?: number[];
  /**
   * The list of relationship group's origin entity index (indexes into `entitiesUIDs`). Values must be positive.
   *
   * @since 5.0
   */
  relationshipsGroupsFrom?: number[];
  /**
   * The list of relationship group's destination entity index (indexes into `entitiesUIDs`). Values must be positive.
   *
   * @since 5.0
   */
  relationshipsGroupsTo?: number[];
  /**
   * The list of relationship's origin entity index (indexes into `entitiesUIDs`).
   *
   * @since 5.0
   */
  relationshipsFrom?: number[];
  /**
   * The list of relationships destination entity index (indexes into `entitiesUIDs`).
   *
   * @since 5.0
   */
  relationshipsTo?: number[];
  /**
   * List of relationships groups indices used by paths. Values must be positive.
   *
   * @since 5.0
   */
  pathsBuffer?: number[];
  /**
   * List of paths relationships groups end indices (indexes into 'PathsBuffer'). Values must be positive.
   *
   * @since 5.0
   */
  pathsEndIndex?: number[];
}